1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (wasAlive: boolean, liveNeighbors: number): boolean =>
15	  liveNeighbors === 3 || (wasAlive && liveNeighbors === 2);
16	
17	type CellTally = { cell: Cell; liveNeighbors: number };
18	
19	const tallyLiveNeighbors = (cells: Cell[]): Map<string, CellTally> => {
20	  const tally = new Map<string, CellTally>();
21	  for (const cell of cells.flatMap(neighborsOf)) {
22	    const key = keyOf(cell);
23	    const existing = tally.get(key);
24	    tally.set(key, { cell, liveNeighbors: (existing?.liveNeighbors ?? 0) + 1 });
25	  }
26	  return tally;
27	};
28	
29	export function nextGeneration(cells: Cell[]): Cell[] {
30	  const aliveKeys = new Set(cells.map(keyOf));
31	
32	  return [...tallyLiveNeighbors(cells)]
33	    .filter(([key, { liveNeighbors }]) => survives(aliveKeys.has(key), liveNeighbors))
34	    .map(([, { cell }]) => cell);
35	}
